import{_ as t,c as l,l as a,a as i,t as o,a4 as r,o as d}from"./chunks/framework.CzsDe1xi.js";const q=JSON.parse('{"title":"MVCC","description":"","frontmatter":{"title":"MVCC"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/事务/MVCC.md","filePath":"packages/doc/src/数据库/Mysql/基础/事务/MVCC.md","lastUpdated":1711622925000}'),n={name:"doc/数据库/Mysql/基础/事务/MVCC.md"},s={id:"frontmatter-title",tabindex:"-1"},c=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),_=r('<h2 id="什么是mvcc" tabindex="-1">什么是MVCC <a class="header-anchor" href="#什么是mvcc" aria-label="Permalink to &quot;什么是MVCC&quot;">​</a></h2><p>MVCC是一种用来解决读写冲突的无锁并发控制，也就是为事务分配单项增长的时间戳，为每个修改保存一个版本，版本与事务时间戳关联，读操作只读该事务开始前的数据库的快照，所以MVCC可以为数据库解决一下问题：</p><ul><li><p>在并发读写数据库时，可以做到在读操作时不用阻塞写操作，写操作也不用阻塞读操作，提高了数据库并发读写的性能。</p></li><li><p>解决脏读、幻读、不可重复读等事务隔离问题，但是不能解决更新丢失问题。</p></li></ul><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><ul><li><p>读写：有线程安全问题，可能会造成事务隔离性问题，可能遇到脏读、幻读、不可重复读</p></li><li><p>写写：有线程安全问题，可能存在更新丢失问题</p></li></ul><h2 id="mysql-mvcc实现原理" tabindex="-1">Mysql MVCC实现原理 <a class="header-anchor" href="#mysql-mvcc实现原理" aria-label="Permalink to &quot;Mysql MVCC实现原理&quot;">​</a></h2><p>依赖以下字段实现</p><ul><li>隐藏字段</li><li>undolog</li><li>read view</li></ul><h3 id="隐藏字段" tabindex="-1">隐藏字段 <a class="header-anchor" href="#隐藏字段" aria-label="Permalink to &quot;隐藏字段&quot;">​</a></h3><p>每行记录除了我们自定义的字段外，还有数据库隐式定义的DB_TRX_ID,DB_ROLL_PTR,DB_ROW_ID等字段</p><p>1、DB_TRX_ID 6字节，最近修改事务id，记录创建这条记录或者最后一次修改该记录的事务id；</p><p>2、DB_ROLL_PTR 7字节，回滚指针，指向这条记录的上一个版本,用于配合undolog，指向上一个旧版本</p><p>3、DB_ROW_JD 6字节，隐藏的主键，如果数据表没有主键，那么innodb会自动生成一个6字节的row_id</p><p>DB_ROW_ID是数据库默认为该行记录生成的唯一隐式主键；</p><p>DB_TRX_ID是当前操作该记录的事务ID；</p><p>DB_ROLL_PTR是一个回滚指针，用于配合undo日志，指向上一个旧版本；</p><h3 id="undo-log" tabindex="-1">undo log <a class="header-anchor" href="#undo-log" aria-label="Permalink to &quot;undo log&quot;">​</a></h3><h3 id="read-view" tabindex="-1">Read View <a class="header-anchor" href="#read-view" aria-label="Permalink to &quot;Read View&quot;">​</a></h3><p>Read View是事务进行快照读操作的时候生产的读视图，在该事务执行快照读的那一刻，会生成一个数据系统当前的快照，记录并维护系统当前活跃事务的id，事务的id值是递增的。</p><p>其实Read View的最大作用是用来做可见性判断的，也就是说当某个事务在执行快照读的时候，对该记录创建一个Read View的视图，把它当作条件去判断当前事务能够看到哪个版本的数据，有可能读取到的是最新的数据，也有可能读取的是当前行记录的undolog中某个版本的数据</p>',20);function p(e,h,u,m,C,V){return d(),l("div",null,[a("h1",s,[i(o(e.$frontmatter.title)+" ",1),c]),_])}const D=t(n,[["render",p]]);export{q as __pageData,D as default};
